features.snippet:
reg [31:0] regs [31:0];
always @(posedge clk or negedge resetb) begin
    if (!resetb) begin
        for (i = 0; i <= 31; i = i + 1) regs[i] <= 32'h0;
    end else if (!stall) begin
        regs[sel] <= datain;
    end
end

input [4:0] sel;
input [31:0] datain;
reg [31:0] regs [31:0];
regs[sel] <= datain;
